import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/personificationService';
import { PersonificationSegment } from '../types';

declare var JSZip: any;

const PersonificationModule: React.FC = () => {
  const storageKey = "personification_project_v1";
  const [state, setState] = useState<any>({
    healthKeyword: '',
    ctaProduct: '',
    frameCount: 4,
    gender: 'Nữ',
    voice: 'Miền Bắc',
    productFiles: [],
    productPreviews: [],
    isGeneratingScript: false,
    segments: []
  });

  const productInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        setState((p: any) => ({ 
          ...p, 
          ...parsed, 
          productFiles: [], 
          productPreviews: [], 
          isGeneratingScript: false,
          segments: (parsed.segments || []).map((s: any) => ({ ...s, image: { ...s.image, url: '' } })) 
        }));
      }
    } catch (e) {}
  }, []);

  useEffect(() => {
    try {
      const { productFiles, productPreviews, isGeneratingScript, segments, ...rest } = state;
      const safeSegments = segments.map((s: any) => ({ ...s, image: { ...s.image, url: '' } }));
      localStorage.setItem(storageKey, JSON.stringify({ ...rest, segments: safeSegments }));
    } catch (e) {}
  }, [state]);

  // Essential: Keep Import/Export functionality
  useEffect(() => {
    const handleExport = () => {
      const exportData = state.segments.map((seg: any, index: number) => ({
        stt: index + 1,
        inputs: {
          healthKeyword: state.healthKeyword,
          ctaProduct: state.ctaProduct,
          settings: {
            gender: state.gender,
            voice: state.voice,
            frameCount: state.frameCount
          }
        },
        script: seg.content,
        outputImage: seg.image?.url || '',
        videoPrompt: seg.videoPrompt?.text || ''
      }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Nhan_Hoa_Bo_Phan' } 
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj || {}).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData)) return;

      const firstItem = importedData[0];
      const inputs = smartFind(firstItem, ['inputs', 'input', 'data']) || {};
      const settings = smartFind(inputs, ['settings', 'config']) || {};

      const newState = {
        ...state,
        healthKeyword: smartFind(inputs, ['healthKeyword', 'keyword', 'chủ đề']) || state.healthKeyword,
        ctaProduct: smartFind(inputs, ['ctaProduct', 'product', 'sản phẩm']) || state.ctaProduct,
        gender: smartFind(settings, ['gender', 'giới tính']) || state.gender,
        voice: smartFind(settings, ['voice', 'giọng']) || state.voice,
        frameCount: smartFind(settings, ['frameCount', 'count']) || importedData.length,
        segments: []
      };

      const total = importedData.length;
      for (let i = 0; i < total; i++) {
        const item = importedData[i];

        newState.segments.push({
          id: i + 1,
          content: smartFind(item, ['script', 'content', 'text']) || '',
          image: { 
            url: smartFind(item, ['outputImage', 'image', 'base64']) || '', 
            loading: false, 
            regenNote: '' 
          },
          videoPrompt: { 
            text: smartFind(item, ['videoPrompt', 'prompt']) || '', 
            loading: false, 
            visible: true 
          }
        });

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent, complete: i === total - 1 } }));
        await new Promise(r => setTimeout(r, 100));
      }

      setState(newState);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [state]);

  const handleProductUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = (Array.from(e.target.files) as File[]).slice(0, 5);
      const urls = files.map(f => URL.createObjectURL(f));
      setState((p: any) => ({ ...p, productFiles: files, productPreviews: urls }));
    }
  };

  const handleGenerateScript = async () => {
    if (!state.healthKeyword || !state.ctaProduct) return;
    setState((p: any) => ({ ...p, isGeneratingScript: true }));
    try {
      const scripts = await service.generatePersonificationScript(
        state.healthKeyword,
        state.ctaProduct,
        state.frameCount,
        state.gender,
        state.voice
      );
      const newSegments: PersonificationSegment[] = scripts.map((content, i) => ({
        id: i + 1,
        content,
        image: { url: '', loading: false, regenNote: '' },
        videoPrompt: { text: '', loading: false, visible: false }
      }));
      setState((p: any) => ({ ...p, segments: newSegments, isGeneratingScript: false }));
    } catch (e) {
      setState((p: any) => ({ ...p, isGeneratingScript: false }));
    }
  };

  const handleGenImage = async (id: number) => {
    const seg = state.segments.find((s: any) => s.id === id);
    if (!seg) return;
    setState((p: any) => ({
      ...p,
      segments: p.segments.map((s: any) => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s)
    }));
    try {
      const productParts = await Promise.all(state.productFiles.map((f: any) => service.fileToGenerativePart(f)));
      const url = await service.generatePersonificationImage(
        seg.content,
        productParts,
        state.healthKeyword,
        state.ctaProduct,
        state.gender,
        seg.image.regenNote
      );
      setState((p: any) => ({
        ...p,
        segments: p.segments.map((s: any) => s.id === id ? { ...s, image: { ...s.image, url, loading: false } } : s)
      }));
    } catch (e) {
      setState((p: any) => ({
        ...p,
        segments: p.segments.map((s: any) => s.id === id ? { ...s, image: { ...s.image, loading: false } } : s)
      }));
    }
  };

  const handleGenPrompt = async (id: number) => {
    const seg = state.segments.find((s: any) => s.id === id);
    if (!seg) return;
    setState((p: any) => ({
      ...p,
      segments: p.segments.map((s: any) => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s)
    }));
    try {
      const prompt = await service.generatePersonificationVeoPrompt(seg.content, state.healthKeyword, state.gender, state.voice);
      setState((p: any) => ({
        ...p,
        segments: p.segments.map((s: any) => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s)
      }));
    } catch (e) {
      setState((p: any) => ({
        ...p,
        segments: p.segments.map((s: any) => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s)
      }));
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') {
      alert("Đang tải thư viện nén, vui lòng thử lại sau giây lát.");
      return;
    }

    const zip = new JSZip();
    let count = 0;

    for (let i = 0; i < state.segments.length; i++) {
      const seg = state.segments[i];
      if (seg.image.url) {
        const base64Data = seg.image.url.split(',')[1];
        if (base64Data) {
          const fileName = `${String(i + 1).padStart(2, '0')}.png`;
          zip.file(fileName, base64Data, { base64: true });
          count++;
        }
      }
    }

    if (count === 0) {
      alert("Không có ảnh nào để tải xuống.");
      return;
    }

    try {
      const content = await zip.generateAsync({ type: "blob" });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `nhan_hoa_images_${Date.now()}.zip`;
      link.click();
      URL.revokeObjectURL(link.href);
    } catch (error) {
      console.error("Lỗi khi tạo file ZIP:", error);
      alert("Có lỗi xảy ra khi đóng gói ảnh.");
    }
  };

  const downloadAllPrompts = () => {
    const text = state.segments
      .map((s: any) => s.videoPrompt.text)
      .filter((t: string) => t)
      .join('\n');
    if (!text) return;
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'nhan_hoa_prompts.txt';
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">1. Ý tưởng / Bài viết nguồn (Source Content)</label>
              <textarea 
                value={state.healthKeyword}
                onChange={e => setState((p: any) => ({ ...p, healthKeyword: e.target.value }))}
                placeholder="Dán bài viết, ý tưởng hoặc các điểm chính về sức khỏe tại đây..."
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 focus:border-orange-500 outline-none transition-all font-medium text-sm h-40 resize-none leading-relaxed"
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">2. Sản phẩm muốn CTA</label>
              <input 
                type="text" 
                value={state.ctaProduct}
                onChange={e => setState((p: any) => ({ ...p, ctaProduct: e.target.value }))}
                placeholder="Ví dụ: trà thải độc gan, kẹo cai thuốc..."
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 focus:border-orange-500 outline-none transition-all font-bold"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">Giới tính nhân vật</label>
                <select 
                  value={state.gender} 
                  onChange={e => setState((p: any) => ({ ...p, gender: e.target.value }))}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 outline-none transition-all font-bold"
                >
                  <option value="Nữ">Nữ</option>
                  <option value="Nam">Nam</option>
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">Giọng điệu vùng miền</label>
                <select 
                  value={state.voice} 
                  onChange={e => setState((p: any) => ({ ...p, voice: e.target.value }))}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 outline-none transition-all font-bold"
                >
                  <option value="Miền Bắc">Miền Bắc (Hà Nội)</option>
                  <option value="Miền Nam">Miền Nam (SÀI GÒN)</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">3. Thời lượng video</label>
              <select 
                value={state.frameCount}
                onChange={e => setState((p: any) => ({ ...p, frameCount: parseInt(e.target.value) }))}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 outline-none transition-all font-bold"
              >
                {Array.from({ length: 12 }, (_, i) => i + 4).map(n => (
                  <option key={n} value={n}>{n} khung hình - {n * 8}s</option>
                ))}
              </select>
            </div>
          </div>

          <div className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">4. Ảnh sản phẩm mẫu (Tối đa 5)</label>
              <div 
                onClick={() => productInputRef.current?.click()}
                className="min-h-[140px] border-2 border-dashed border-slate-200 rounded-2xl flex items-center justify-center bg-slate-50 cursor-pointer hover:bg-slate-100 hover:border-orange-400 transition-all overflow-hidden p-2"
              >
                {state.productPreviews.length > 0 ? (
                  <div className="grid grid-cols-5 gap-2 w-full">
                    {state.productPreviews.map((url: string, i: number) => (
                      <img key={i} src={url} className="w-full aspect-square object-cover rounded-lg" />
                    ))}
                  </div>
                ) : (
                  <div className="text-center">
                    <svg className="w-8 h-8 text-slate-300 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tải ảnh sản phẩm</span>
                  </div>
                )}
                <input type="file" multiple ref={productInputRef} onChange={handleProductUpload} className="hidden" accept="image/*" />
              </div>
            </div>

            <button 
              onClick={handleGenerateScript}
              disabled={state.isGeneratingScript || !state.healthKeyword || !state.ctaProduct}
              className="w-full py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl shadow-orange-100 hover:bg-orange-700 transition-all disabled:opacity-50 active:scale-95 flex items-center justify-center gap-3 uppercase tracking-tighter"
            >
              {state.isGeneratingScript ? (
                <>
                  <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                  XỬ LÝ KỊCH BẢN...
                </>
              ) : "BẮT ĐẦU TẠO KỊCH BẢN"}
            </button>
          </div>
        </div>
      </div>

      {state.segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="flex justify-between items-center bg-slate-900 p-6 rounded-2xl border border-slate-800">
            <div>
              <h3 className="text-xl font-black text-white uppercase tracking-tight">Kịch bản chi tiết ({state.frameCount} khung)</h3>
              <p className="text-xs text-orange-500 font-bold uppercase">Giọng {state.gender} {state.voice} - Gen Z Style</p>
            </div>
            <div className="flex gap-4">
              <button onClick={downloadAllImages} className="px-6 py-3 bg-white text-slate-900 text-xs font-black rounded-xl hover:bg-slate-100 transition-all uppercase">Tải Toàn Bộ Ảnh (ZIP)</button>
              <button onClick={downloadAllPrompts} className="px-6 py-3 bg-orange-600 text-white text-xs font-black rounded-xl hover:bg-orange-700 transition-all uppercase">Tải Prompt (.txt)</button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {state.segments.map((seg: any) => (
              <div key={seg.id} className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full group hover:shadow-xl transition-all">
                <div className="relative aspect-[9/16] bg-slate-100 overflow-hidden">
                  {seg.image.url ? (
                    <img src={seg.image.url} className="w-full h-full object-cover" />
                  ) : (
                    <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
                      {seg.image.loading ? (
                        <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                      ) : (
                        <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest leading-loose">Nhấn nút bên dưới để tạo ảnh</span>
                      )}
                    </div>
                  )}
                  <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md text-white text-[10px] font-black px-3 py-1.5 rounded-full border border-slate-700">
                    CẢNH #{seg.id}
                  </div>
                </div>

                <div className="p-6 flex flex-col flex-1 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-orange-600 uppercase">Lời thoại nhân vật:</label>
                    <textarea 
                      value={seg.content}
                      onChange={e => setState((p: any) => ({
                        ...p,
                        segments: p.segments.map((s: any) => s.id === seg.id ? { ...s, content: e.target.value } : s)
                      }))}
                      className="w-full h-32 p-3 text-xs font-bold text-slate-700 bg-slate-50 border border-100 rounded-xl focus:bg-white focus:border-orange-500 transition-all outline-none resize-none leading-relaxed"
                    />
                    <div className="text-right">
                      <span className={`text-[8px] font-black ${seg.content.length > 190 ? 'text-red-500' : 'text-slate-300'}`}>
                        {seg.content.length}/190
                      </span>
                    </div>
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase">Ghi chú sửa ảnh:</label>
                    <textarea 
                      value={seg.image.regenNote}
                      onChange={e => setState((p: any) => ({
                        ...p,
                        segments: p.segments.map((s: any) => s.id === seg.id ? { ...s, image: { ...s.image, regenNote: e.target.value } } : s)
                      }))}
                      placeholder="VD: Đổi nền sáng hơn..."
                      className="w-full h-16 p-3 text-[10px] font-bold text-slate-500 bg-slate-50 border border-slate-100 border-dashed rounded-xl outline-none resize-none"
                    />
                  </div>

                  <div className="mt-auto grid grid-cols-2 gap-2 pt-4">
                    <button 
                      onClick={() => handleGenImage(seg.id)}
                      disabled={seg.image.loading}
                      className="py-3 bg-slate-900 text-white text-[10px] font-black rounded-xl hover:bg-black transition-all uppercase tracking-tighter"
                    >
                      {seg.image.url ? "Tạo lại ảnh" : "Tạo ảnh 3D"}
                    </button>
                    <button 
                      onClick={() => handleGenPrompt(seg.id)}
                      disabled={seg.videoPrompt.loading}
                      className="py-3 bg-orange-50 text-orange-600 text-[10px] font-black rounded-xl border border-orange-100 hover:bg-orange-100 transition-all uppercase tracking-tighter"
                    >
                      Prompt
                    </button>
                  </div>
                </div>

                {seg.videoPrompt.visible && (
                  <div className="p-4 bg-slate-900 border-t border-slate-800 animate-slideUp">
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-[8px] font-black text-orange-500 uppercase">Video Prompt sẵn sàng</span>
                      <button 
                        onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)}
                        className="text-[8px] font-black text-white underline"
                      >
                        COPY
                      </button>
                    </div>
                    <p className="text-[9px] text-slate-300 leading-tight line-clamp-4 italic opacity-80 font-medium">
                      "{seg.videoPrompt.text}"
                    </p>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default PersonificationModule;

import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const generatePersonificationScript = async (
  healthKeyword: string,
  ctaProduct: string,
  frameCount: number,
  gender: string,
  voice: string
): Promise<string[]> => {
  const ai = getAiClient();

  let dialectInstruction = "";
  if (voice === 'Miền Bắc') {
    dialectInstruction = `
      VĂN PHONG MIỀN BẮC (HÀ NỘI):
      - Sử dụng từ đệm: "nhé", "ạ", "thế", "đấy", "vậy", "vâng", "chứ".
      - Cách dùng từ: "không", "vẫn", "thế này".
      - TUYỆT ĐỐI KHÔNG dùng các từ miền Nam như: nha, nè, nghen, thiệt, hông, vầy.
    `;
  } else {
    dialectInstruction = `
      VĂN PHONG MIỀN NAM (SÀI GÒN):
      - Sử dụng từ đệm: "nha", "nè", "nghen", "hen", "đó", "vầy", "nghen", "ha".
      - Cách dùng từ: "hông" (thay cho không), "thiệt" (thay cho thật), "dễ thương", "hết sảy".
      - TUYỆT ĐỐI KHÔNG dùng các từ miền Bắc như: nhé, ạ, thế, đấy, chả, vâng.
    `;
  }

  const prompt = `
    Nhiệm vụ: Tạo kịch bản TikTok nhân hóa bộ phận cơ thể dựa trên NỘI DUNG NGUỒN được cung cấp.
    NỘI DUNG NGUỒN (BÀI VIẾT/Ý TƯỞNG): "${healthKeyword}"
    SẢN PHẨM CTA: "${ctaProduct}"
    SỐ KHUNG HÌNH: ${frameCount}
    GIỚI TÍNH NHÂN VẬT: ${gender}
    GIỌNG ĐIỆU: ${voice}

    HƯỚNG DẪN XỬ LÝ:
    1. Phân tích nội dung nguồn để tìm ra bộ phận cơ thể liên quan nhất (Ví dụ: bài viết về rượu -> Gan, bài viết về thức khuya -> Mắt/Da...).
    2. Tạo kịch bản từ góc nhìn của bộ phận đó đang "tâm sự" hoặc "mắng" chủ nhân dựa trên thông tin trong bài viết.

    Cấu trúc kịch bản:
    - Các khung đầu: Hook (mở đầu gây sốc/tò mò dựa trên insight bài viết).
    - Các khung giữa: Body (nỗi đau/giải pháp từ góc nhìn bộ phận cơ thể).
    - Các khung kế cuối: Giới thiệu công dụng sản phẩm "${ctaProduct}".
    - Khung cuối: CTA kêu gọi hành động.

    YÊU CẦU NGÔN NGỮ:
    - Giọng điệu: ${voice}. ${dialectInstruction}
    - Phong cách: Suồng sã, đời thường, dùng slang Gen Z (ví dụ: "ét ô ét", "chê", "mãi mận", "ra dẻ", "cứu tui"), châm biếm, hài hước thâm thúy.
    - Ngôi xưng: "Tôi" (bộ phận cơ thể) và "Bạn/Chủ nhân" (người xem).
    - Độ dài: Bắt buộc từ 160-190 ký tự mỗi đoạn.

    YÊU CẦU ĐẦU RA:
    - Trả về đúng ${frameCount} đoạn kịch bản.
    - Kết quả là một mảng JSON các chuỗi ký tự.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: { 
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Script generation failed", e);
    return [];
  }
};

export const generatePersonificationImage = async (
  script: string,
  productImages: any[],
  healthKeyword: string,
  ctaProduct: string,
  gender: string,
  regenNote: string = ""
): Promise<string> => {
  const ai = getAiClient();

  const isProductSection = script.toLowerCase().includes(ctaProduct.toLowerCase()) || 
                          script.toLowerCase().includes("sản phẩm") || 
                          script.toLowerCase().includes("cta");

  const prompt = `
    Style: 3D Animation Pixar/Disney style, vibrant colors, high quality.
    Setting: Inside the human body (stylized and clean).
    Character: A personified body part related to the context: "${healthKeyword.substring(0, 500)}". 
    Gender identity of character: ${gender}.
    The character must be cute/funny with expressive face, arms, legs, and a moving mouth. 
    Personality: Sassy, bossy, or pitiful based on context.

    Action: "${script}".
    ${isProductSection ? `The character is naturally holding or using the product: "${ctaProduct}".` : ""}

    MANDATORY: 
    - NO TEXT, NO SUBTITLES, NO OVERLAYS.
    - 3D CGI look.
    ${regenNote ? `Additional instruction: ${regenNote}` : ""}
  `;

  const contents: any[] = [{ text: prompt }];
  productImages.forEach(img => contents.push({ inlineData: img }));

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (e) {
    console.error("Image generation failed", e);
    throw e;
  }
};

export const generatePersonificationVeoPrompt = async (
  script: string,
  healthKeyword: string,
  gender: string,
  voice: string
): Promise<string> => {
  const ai = getAiClient();
  const systemPrompt = `
    Bạn là chuyên gia viết prompt cho AI Video (VEO-3). Dựa trên kịch bản nhân hóa: "${script}", hãy tạo một prompt video hoàn chỉnh.

    CẤU TRÚC PROMPT (VIẾT LIỀM MẠCH TRÊN 1 DÒNG):
    Đoạn 1: Nhân vật & bối cảnh. (Mô tả bộ phận cơ thể liên quan đến nội dung nguồn: ${healthKeyword.substring(0, 200)} được nhân hóa thành nhân vật 3D sống động có tay chân, bối cảnh bên trong cơ thể, giới tính phong cách ${gender}).
    Đoạn 2: Hành động & tương tác. (Mô tả nhân vật đang nói chuyện hoặc hành động khớp với kịch bản, không tự ý thêm sản phẩm lạ trừ khi kịch bản yêu cầu).
    Đoạn 3: Góc quay & chuyển động máy. (Sáng tạo các chuyển động máy camera 3D mượt mà).
    Đoạn 4: Hậu cảnh & đạo cụ. (Mô tả chi tiết môi trường nội tạng được nghệ thuật hóa).
    Đoạn 5: Lời thoại (QUAN TRỌNG NHẤT):
    ✨ Model speaks in ${voice} voice (${gender === 'Nữ' ? 'Female' : 'Male'}): "${script}"
    Đoạn 6: Thông số kỹ thuật. (9:16, 4K, Realistic style, Cinematic lighting, 3D Animation style).

    YÊU CẦU ĐẦU RA: Chỉ trả về 1 dòng văn bản duy nhất bằng Tiếng Việt.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [{ text: systemPrompt }] }
  });
  return response.text?.trim().replace(/\n/g, ' ') || "";
};

