export const generatePovSegments = async (
  analysis: string, 
  style: string, 
  count: number, 
  gender: string, 
  voice: string, 
  charDesc: string, 
  contextNote: string
): Promise<string[]> => {
  const ai = getAiClient();

  let dialectInstruction = "";
  if (voice === 'Miền Bắc') {
    dialectInstruction = `
      NGÔN NGỮ CHUẨN NGƯỜI HÀ NỘI (MIỀN BẮC):
      - Dùng các từ đệm: "nhé", "ạ", "thế", "đấy", "chứ", "không", "vẫn".
      - TUYỆT ĐỐI KHÔNG dùng: nha, nè, hông, thiệt.
    `;
  } else {
    dialectInstruction = `
      NGÔN NGỮ CHUẨN NGƯỜI SÀI GÒN (MIỀN NAM):
      - Dùng các từ đệm: "nha", "nè", "nghen", "hen", "đó", "vầy".
      - Cách dùng từ: "hông" (không), "thiệt" (thật).
      - TUYỆT ĐỐI KHÔNG dùng: nhé, ạ, thế, đấy.
    `;
  }

  const prompt = `
    Dựa trên bản phân tích nội dung sau: "${analysis}".
    Hãy tạo ra một kịch bản POV mới hoàn toàn, phong cách: "${style}".

    YÊU CẦU VỀ NỘI DUNG KỊCH BẢN (CỰC KỲ QUAN TRỌNG):
    1. Kịch bản CHỈ bao gồm lời thoại (dialogue) hoặc lời dẫn truyện (narration).
    2. TUYỆT ĐỐI KHÔNG mô tả nhân vật vào nội dung kịch bản (ví dụ: KHÔNG viết "Cô gái xinh đẹp nói...", "Mặc áo đỏ...").
    3. TUYỆT ĐỐI KHÔNG mô tả bối cảnh vào nội dung kịch bản (ví dụ: KHÔNG viết "Trong căn phòng...", "Dưới ánh nắng...").
    4. TUYỆT ĐỐI KHÔNG viết các ghi chú hành động hoặc cảm xúc trong ngoặc (ví dụ: KHÔNG viết "(cười)", "(khóc)", "(đi bộ)").
    5. Nội dung kịch bản phải thuần túy là câu nói tự nhiên dựa trên "${analysis}".

    THÔNG TIN THAM KHẢO (Dùng để định hướng nội dung nhưng KHÔNG viết vào kịch bản):
    - Giới tính nhân vật chính: ${gender}.
    - Mô tả nhân vật: ${charDesc}.
    - Ghi chú bối cảnh: ${contextNote}.

    YÊU CẦU NGÔN NGỮ:
    - Vùng miền: ${voice}.
    ${dialectInstruction}
    - Xưng hô "mình", "em", "mình" một cách tự nhiên tùy theo ngữ cảnh POV.

    YÊU CẦU CẤU TRÚC:
    - Chia kịch bản thành đúng ${count} đoạn nhỏ.
    - Mỗi đoạn từ 150 đến 190 ký tự.
    - Trả về kết quả dưới dạng một mảng JSON các chuỗi ký tự.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: { 
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });

    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Parse script error", e);
    return [];
  }
};

export const generatePovImage = async (
  script: string, 
  facePart: any | null, 
  gender: string, 
  charDesc: string,
  regenNote: string = "",
  imageStyle: 'Realistic' | '3D' = 'Realistic',
  contextNote: string = "",
  outfitPart: any | null = null
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-2.5-flash-image";
  const is3D = imageStyle === '3D';

  const baseStyle = is3D 
    ? "3D Animation Pixar/Disney style, vibrant colors, expressive 3D character design, high-quality CGI."
    : "Photorealistic RAW PHOTO, 8k resolution, authentic textures, cinematic lighting.";

  const faceInstruction = facePart 
    ? "Maintain the exact facial features of the person in the provided face reference image." 
    : `Appearance: Vietnamese ${gender}. ${charDesc}`;

  const outfitInstruction = outfitPart 
    ? "The character MUST wear the exact outfit shown in the OUTFIT_REFERENCE image. Match the style, fabric, and colors perfectly."
    : "The character wears an outfit matching the description: " + charDesc;

  const characterFidelityRule = charDesc ? `
    CRITICAL CHARACTER FIDELITY (MANDATORY):
    - You MUST follow these specific appearance details for the character: "${charDesc}".
    - DO NOT deviate from the described age, physique, or personality.
    - The character must look EXACTLY as described in every detail.
    ${is3D ? "- Translate these details into a cute and stylized 3D character design." : ""}
  ` : "";

  const backgroundRule = contextNote ? `
    CRITICAL BACKGROUND INSTRUCTION (PRIORITY):
    - You MUST place the character in the following environment: "${contextNote}".
    - Strictly adhere to all details, objects, and atmosphere described in this background note.
  ` : "ENVIRONMENT: Natural lifestyle setting appropriate for the scene.";

  const prompt = `
    ${baseStyle} 9:16 aspect ratio.
    Subject: ${faceInstruction}.
    ${outfitInstruction}
    Action/Scene: "${script}".

    ${characterFidelityRule}
    ${backgroundRule}


    CRITICAL VISUAL RULES (STRICT NO-TEXT & NO-UI POLICY):
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS.
    2. The background must be CLEAN and FREE of signage, posters, labels, or written words.
    3. If the context implies a screen or sign, leave it BLANK or Abstract.
    4. NO UI elements, NO speech bubbles, NO watermarks, NO subtitles.
    5. The image must be purely visual storytelling.
    6. ABSOLUTELY NO ICONS, NO GRAPHICS, NO EMOJIS, NO VISUAL EFFECTS, NO OVERLAYS.
    7. Do NOT simulate TikTok UI or video editing effects. It must look like a RAW PHOTO.

    CRITICAL RESTRICTIONS & RULES: 
    1. NO CHILDREN, NO KIDS, NO BABIES. The subject must be an adult.
    2. ${is3D ? "Must look like high-quality 3D CGI." : "Must look like a real photo."}

    MANDATORY: NO TEXT, NO SUBTITLES, NO OVERLAYS, NO ICONS, NO GRAPHICS, NO EMOJIS, NO VISUAL EFFECT.
    ${regenNote ? `Additional Feedback: ${regenNote}` : ""}
  `;

  const parts: any[] = [{ text: prompt }];
  if (facePart) parts.push({ inlineData: facePart });
  if (outfitPart) parts.push({ inlineData: outfitPart });

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (error) {
    console.error("Image generation failed:", error);
    throw error;
  }
};

export const formatVideoPrompt = async (
  script: string, 
  gender: string, 
  voice: string, 
  charDesc: string, 
  contextNote: string,
  imageStyle: 'Realistic' | '3D' = 'Realistic',
  generatedImageBase64?: string
): Promise<string> => {
    const ai = getAiClient();
    const is3D = imageStyle === '3D';
    const voiceTag = voice === 'Miền Bắc' ? 'Northern Vietnamese' : 'Southern Vietnamese';
    const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

    const systemPrompt = `
    Bạn là chuyên gia viết prompt cho AI Video (VEO-3). Nhiệm vụ của bạn là viết một bản mô tả chi tiết để chuyển hóa hình ảnh tĩnh thành video POV sinh động.

    NGUYÊN TẮC QUAN TRỌNG (BẮT BUỘC):
    1. MÔ TẢ DỰA TRÊN HÌNH ẢNH THAM CHIẾU: Bạn phải nhìn kỹ ảnh được cung cấp và mô tả lại ĐÚNG nhân vật (trang phục, kiểu tóc, gương mặt) và bối cảnh (vật dụng xung quanh, ánh sáng) đang xuất hiện trong đó.
    2. KHÔNG TỰ Ý BỊA ĐẶT: Tuyệt đối không thêm thắt các chi tiết bối cảnh lạ lẫm không có trong ảnh.
    3. TƯƠNG THÍCH KỊCH BẢN: Biểu cảm gương mặt và cử động của nhân vật phải khớp với nội dung kịch bản nói: "${script}".
    4. DUY TRÌ TÍNH NHẤT QUÁN: Đảm bảo nhân vật trong video giống hệt nhân vật trong ảnh.

    PHONG CÁCH VIDEO: ${is3D ? "3D Animation / CGI Style" : "Photorealistic / Real Life Style"}.

    CẤU TRÚC PHẢI TUÂN THỦ 6 ĐOẠN (VIẾT LIỀM MẠCH TRÊN 1 DÒNG):
    Đoạn 1: Nhân vật & bối cảnh. (Dựa trên ảnh: Nhân vật người Việt Nam ${gender}, mặc đồ như trong ảnh. ${is3D ? "Phong cách hoạt hình 3D." : "Phong cách người thật."} Video 9:16).
    Đoạn 2: Hành động & tương tác. (Mô tả hành động nhân vật nói chuyện, biểu cảm phù hợp lời thoại: "${script}").
    Đoạn 3: Góc quay & chuyển động máy. (Cách nhân vật di chuyển và tương tác với Camera. Có Pan hoặc Dolly hoặc zoom hoặc tracking shot vào nhân vật (tuyệt đối không thay đổi bối cảnh và nhân vật).
    Đoạn 4: Hậu cảnh & đạo cụ. (Mô tả chi tiết các vật thể đang có trong ảnh tham chiếu. Lưu ý bối cảnh/cấm kỵ: ${contextNote}).
    Đoạn 5: Lời thoại (QUAN TRỌNG NHẤT): ✨ Model speaks in ${voiceTag} voice (${voiceGender}): "${script}"
    Đoạn 6: Thông số kỹ thuật. (9:16, 4K, ${is3D ? "3D Animation, Masterpiece CGI, 60fps" : "Realistic, Cinematic Lighting, Photorealistic, 60fps"}).

    YÊU CẦU ĐẦU RA: Chỉ trả về 1 dòng Tiếng Anh duy nhất (trừ phần lời thoại).
    `;

    const parts: any[] = [{ text: systemPrompt }];
    if (generatedImageBase64) {
      parts.push({ 
        inlineData: { 
          mimeType: 'image/png', 
          data: generatedImageBase64.split(',')[1] || generatedImageBase64 
        } 
      });
    }

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: { parts }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
};

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/videoPovService';
import { PovScriptSegment } from '../types';

declare var JSZip: any;

const STYLES = [
    { id: 'tâm sự trải lòng', label: 'Tâm sự trải lòng (Deep/Emotional)' },
    { id: 'vui vẻ hài hước', label: 'Vui vẻ hài hước (Funny/Humorous)' },
    { id: 'kịch tính & cảm xúc', label: 'Kịch tính & cảm xúc (Dramatic)' },
    { id: 'chuyên gia phân tích', label: 'Chuyên gia phân tích (Analytical)' },
    { id: 'kể chuyện drama', label: 'Kể chuyện Drama (Storytelling)' },
    { id: 'vlog đời thường', label: 'Vlog đời thường (Daily Vlog)' },
    { id: 'hào hứng bắt trend', label: 'Hào hứng - Bắt trend (Excited/Trendy)' },
    { id: 'thư giãn healing', label: 'Thư giãn - Healing (Chill)' },
    { id: 'châm biếm sarki', label: 'Châm biếm - Sarky (Sarcastic)' }
];

const SCENE_COUNT_OPTIONS = Array.from({ length: 20 }, (_, i) => {
    const count = i + 3;
    const seconds = count * 8;
    return { count, label: `${count} cảnh - ${seconds}s` };
});

const VideoPovModule: React.FC = () => {
  const storageKey = "videopov_project_v15_extract";
  const [state, setState] = useState<any>({
    videoFile: null,
    videoPreviewUrl: null,
    originalScriptInput: '',
    analysis: '',
    isAnalyzing: false,
    style: 'châm biếm sarky',
    gender: 'Nữ',
    voice: 'Miền Bắc',
    imageStyle: 'Realistic',
    characterDescription: '',
    outfitFile: null,
    outfitPreviewUrl: null,
    isExtractingOutfit: false,
    contextNote: '',
    segmentCount: 5,
    faceFile: null,
    facePreviewUrl: null,
    isGeneratingScript: false,
    segments: []
  });

  const videoInputRef = useRef<HTMLInputElement>(null);
  const faceInputRef = useRef<HTMLInputElement>(null);
  const outfitInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
          const parsed = JSON.parse(saved);
          if (parsed && typeof parsed === 'object') {
            setState((p:any)=>({
                ...p, 
                ...parsed, 
                videoFile: null, 
                videoPreviewUrl: null, 
                faceFile: null, 
                facePreviewUrl: null,
                outfitFile: null,
                isExtractingOutfit: false,
                isAnalyzing: false,
                isGeneratingScript: false,
                segments: (parsed.segments || []).map((seg: any) => ({
                    ...seg,
                    image: seg.image || { url: '', loading: false, regenNote: '' },
                    videoPrompt: seg.videoPrompt || { text: '', loading: false, visible: false }
                }))
            }));
          }
      }
    } catch (e) {}
  }, []);

  useEffect(() => {
    try {
      const { videoFile, videoPreviewUrl, faceFile, facePreviewUrl, outfitFile, segments, isAnalyzing, isGeneratingScript, isExtractingOutfit, ...persistent } = state;
      const safeSegments = (segments || []).map((seg: any) => ({
        ...seg,
        image: { ...(seg.image || {}), url: '' }
      }));
      localStorage.setItem(storageKey, JSON.stringify({ ...persistent, segments: safeSegments }));
    } catch (e) {}
  }, [state]);

  useEffect(() => {
    const handleExport = () => {
      const exportData = state.segments.map((seg: any, index: number) => ({
        stt: index + 1,
        inputs: {
          originalAnalysis: state.analysis,
          characterDescription: state.characterDescription,
          contextNote: state.contextNote,
          outfitImage: state.outfitPreviewUrl || '',
          settings: {
            style: state.style,
            gender: state.gender,
            voice: state.voice,
            imageStyle: state.imageStyle
          }
        },
        script: seg.content,
        outputImage: seg.image?.url || '',
        videoPrompt: seg.videoPrompt?.text || ''
      }));
      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { detail: { data: exportData, moduleName: 'Video_POV' } }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj || {}).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData)) return;
      const firstItem = importedData[0];
      const inputs = smartFind(firstItem, ['inputs', 'input', 'data']) || {};
      const settings = smartFind(inputs, ['settings', 'config']) || {};

      const newState = {
        ...state,
        analysis: smartFind(inputs, ['originalAnalysis', 'analysis', 'phân tích']) || state.analysis,
        characterDescription: smartFind(inputs, ['characterDescription', 'character']) || state.characterDescription,
        contextNote: smartFind(inputs, ['contextNote', 'context', 'bối cảnh']) || state.contextNote,
        outfitPreviewUrl: smartFind(inputs, ['outfitImage', 'outfit']) || state.outfitPreviewUrl,
        style: smartFind(settings, ['style', 'phong cách']) || state.style,
        gender: smartFind(settings, ['gender', 'giới tính']) || state.gender,
        voice: smartFind(settings, ['voice', 'giọng']) || state.voice,
        imageStyle: smartFind(settings, ['imageStyle']) || state.imageStyle,
        segmentCount: importedData.length,
        segments: []
      };

      const total = importedData.length;
      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        newState.segments.push({
          id: i + 1,
          content: smartFind(item, ['script', 'content', 'text']) || '',
          image: { url: smartFind(item, ['outputImage', 'image', 'base64']) || '', loading: false, regenNote: '' },
          videoPrompt: { text: smartFind(item, ['videoPrompt', 'prompt']) || '', loading: false, visible: true }
        });
        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent, complete: i === total - 1 } }));
        await new Promise(r => setTimeout(r, 100));
      }
      setState(newState);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [state]);

  const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
        const file = e.target.files[0];
        setState((p:any)=>({...p, videoFile: file, videoPreviewUrl: URL.createObjectURL(file), originalScriptInput: ''}));
    }
  };

  const handleFaceUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
        const file = e.target.files[0];
        setState((p:any)=>({...p, faceFile: file, facePreviewUrl: URL.createObjectURL(file)}));
    }
  };

  const handleOutfitUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
        const file = e.target.files[0];
        setState((p:any)=>({...p, outfitFile: file, outfitPreviewUrl: URL.createObjectURL(file)}));
    }
  };

  const handleRemoveOutfit = (e: React.MouseEvent) => {
    e.stopPropagation();
    setState((p:any)=>({...p, outfitFile: null, outfitPreviewUrl: null}));
    if (outfitInputRef.current) outfitInputRef.current.value = "";
  };

  const handleExtractOutfit = async () => {
    let part = null;
    if (state.outfitFile) {
        part = await service.fileToGenerativePart(state.outfitFile);
    } else if (state.outfitPreviewUrl?.startsWith('data:')) {
        part = { mimeType: 'image/png', data: state.outfitPreviewUrl.split(',')[1] };
    }
    if (!part) return;
    setState((p:any) => ({ ...p, isExtractingOutfit: true }));
    try {
      const desc = await service.describePovOutfit(part);
      setState((p:any) => ({ ...p, characterDescription: desc, isExtractingOutfit: false }));
    } catch (e) {
      setState((p:any) => ({ ...p, isExtractingOutfit: false }));
    }
  };

  const handleAnalyze = async () => {
    if (!state.videoFile && !state.originalScriptInput.trim()) return;
    setState((p:any)=>({...p, isAnalyzing: true}));
    try {
        let res = "";
        if (state.videoFile) {
            res = await service.analyzeVideoContent(state.videoFile);
        } else {
            res = await service.analyzeTextContent(state.originalScriptInput);
        }
        setState((p:any)=>({...p, analysis: res, isAnalyzing: false}));
    } catch(e) {
        setState((p:any)=>({...p, isAnalyzing: false}));
    }
  };

  const handleGenScript = async () => {
      if (!state.analysis) return;
      setState((p:any)=>({...p, isGeneratingScript: true}));
      try {
          const scripts = await service.generatePovSegments(
              state.analysis, 
              state.style, 
              state.segmentCount, 
              state.gender, 
              state.voice,
              state.characterDescription,
              state.contextNote
          );
          const newSegments: PovScriptSegment[] = scripts.map((content: string, i: number) => ({
              id: i + 1,
              content: content,
              image: { url: '', loading: false, regenNote: '' },
              videoPrompt: { text: '', loading: false, visible: false }
          }));
          setState((p:any)=>({...p, segments: newSegments, isGeneratingScript: false}));
      } catch(e) {
          setState((p:any)=>({...p, isGeneratingScript: false}));
      }
  };

  const handleGenImage = async (id: number) => {
      const seg = state.segments.find((s:any)=>s.id === id);
      if (!seg) return;
      setState((p:any)=>({...p, segments: p.segments.map((s:any)=>s.id===id?{...s, image:{...s.image, loading:true}}:s)}));
      try {
          const facePart = state.faceFile ? await service.fileToGenerativePart(state.faceFile) : null;
          const outfitPart = state.outfitFile ? await service.fileToGenerativePart(state.outfitFile) : null;
          const url = await service.generatePovImage(
              seg.content, 
              facePart, 
              state.gender, 
              state.characterDescription,
              seg.image.regenNote,
              state.imageStyle,
              state.contextNote,
              outfitPart
          );
          setState((p:any)=>({...p, segments: p.segments.map((s:any)=>s.id===id?{...s, image:{...s.image, url, loading:false}}:s)}));
      } catch(e) {
          setState((p:any)=>({...p, segments: p.segments.map((s:any)=>s.id===id?{...s, image:{...s.image, loading:false}}:s)}));
      }
  };

  const handleGenPrompt = async (id: number) => {
      const seg = state.segments.find((s:any)=>s.id === id);
      if (!seg) return;
      setState((p:any)=>({...p, segments: p.segments.map((s:any)=>s.id===id?{...s, videoPrompt:{...s.videoPrompt, loading:true, visible:true}}:s)}));
      try {
          const prompt = await service.formatVideoPrompt(
              seg.content, 
              state.gender, 
              state.voice,
              state.characterDescription,
              state.contextNote,
              state.imageStyle,
              seg.image?.url
          );
          setState((p:any)=>({...p, segments: p.segments.map((s:any)=>s.id===id?{...s, videoPrompt:{text: prompt, loading:false, visible:true}}:s)}));
      } catch(e) {
          setState((p:any)=>({...p, segments: p.segments.map((s:any)=>s.id===id?{...s, videoPrompt:{...s.videoPrompt, loading:false}}:s)}));
      }
  };

  const handleBulkPrompt = async () => {
      for (const seg of state.segments) { await handleGenPrompt(seg.id); }
  };

  const downloadAllImagesZip = async () => {
    if (typeof JSZip === 'undefined') return alert("Đang tải thư viện nén...");
    const zip = new JSZip();
    let count = 0;
    for (let i = 0; i < state.segments.length; i++) {
      const seg = state.segments[i];
      if (seg.image?.url) {
        const base64Data = seg.image.url.split(',')[1];
        if (base64Data) { zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64Data, { base64: true }); count++; }
      }
    }
    if (count === 0) return alert("Không có ảnh nào.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `pov_images_${Date.now()}.zip`;
    link.click();
  };

  const downloadAllPromptsTxt = () => {
    const text = (state.segments || [])
      .map((s: any) => s.videoPrompt?.text || "")
      .filter((t: string) => t.trim().length > 0)
      .join('\n');
    if (!text) return alert("Vui lòng tạo Video Prompt.");
    const blob = new Blob([text], { type: 'text/plain' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `prompts_pov_${Date.now()}.txt`;
    link.click();
  };

  const hasAnyMedia = state.segments.some((seg: any) => seg.image?.url || seg.videoPrompt?.text);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
        <div className="bg-white rounded-[24px] p-8 border border-slate-200 shadow-sm mb-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
            <div className="lg:col-span-4 space-y-6">
                <div>
                    <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">1a. Video gốc (Nguồn phân tích):</label>
                    <div 
                        onClick={() => videoInputRef.current?.click()} 
                        className="aspect-video border-2 border-dashed border-slate-200 rounded-xl flex items-center justify-center bg-slate-50 cursor-pointer overflow-hidden hover:border-orange-400 transition-all"
                    >
                        {state.videoPreviewUrl ? (
                            <video src={state.videoPreviewUrl} className="h-full w-full object-cover" controls={false} autoPlay muted loop />
                        ) : (
                            <div className="text-center">
                                <svg className="w-10 h-10 text-slate-300 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                                <span className="text-[10px] font-black uppercase tracking-tighter">Tải Video</span>
                            </div>
                        )}
                    </div>
                    <input type="file" ref={videoInputRef} onChange={handleVideoUpload} className="hidden" accept="video/*" />
                </div>

                <div className="relative flex items-center py-2">
                    <div className="flex-grow border-t border-slate-100"></div>
                    <span className="flex-shrink mx-4 text-[10px] font-bold text-slate-300 uppercase tracking-widest">- HOẶC -</span>
                    <div className="flex-grow border-t border-slate-100"></div>
                </div>

                <div>
                    <div className="flex justify-between items-center mb-2">
                        <label className="block text-[10px] font-black text-slate-500 uppercase">1b. Nhập kịch bản gốc:</label>
                    </div>
                    <textarea 
                        value={state.originalScriptInput}
                        onChange={e => setState((p:any)=>({...p, originalScriptInput: e.target.value, videoFile: null, videoPreviewUrl: null}))}
                        placeholder="Paste nội dung truyện, tâm sự..."
                        className="w-full h-32 p-4 border border-slate-200 rounded-xl text-xs bg-slate-50 outline-none transition-all resize-none font-medium focus:bg-white focus:border-orange-500"
                    />
                </div>

                <div>
                    <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">2. Ảnh khuôn mặt mẫu (Tùy chọn):</label>
                    <div 
                        onClick={() => faceInputRef.current?.click()} 
                        className="h-28 border-2 border-dashed border-slate-200 rounded-xl flex items-center justify-center bg-slate-50 cursor-pointer hover:bg-slate-100 hover:border-orange-400 transition-all overflow-hidden"
                    >
                        {state.facePreviewUrl ? (
                            <img src={state.facePreviewUrl} className="h-full object-contain" />
                        ) : (
                            <div className="flex items-center gap-2 text-slate-300">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>
                                <span className="text-[10px] font-black uppercase tracking-tighter">Tải ảnh mặt</span>
                            </div>
                        )}
                    </div>
                    <input type="file" ref={faceInputRef} onChange={handleFaceUpload} className="hidden" accept="image/*" />
                </div>
            </div>

            <div className="lg:col-span-8 space-y-6">
                <div className="flex justify-between items-end">
                    <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest">3. Phân tích nội dung:</label>
                    <button 
                        onClick={handleAnalyze} 
                        disabled={state.isAnalyzing || (!state.videoFile && !state.originalScriptInput.trim())} 
                        className="text-[10px] font-black px-4 py-2 bg-orange-50 text-orange-600 rounded-lg border border-orange-100 hover:bg-orange-100 disabled:opacity-50 transition-all uppercase tracking-widest"
                    >
                        {state.isAnalyzing ? "Đang phân tích..." : "Bắt đầu phân tích"}
                    </button>
                </div>
                <textarea 
                    value={state.analysis} 
                    onChange={e => setState((p:any)=>({...p, analysis: e.target.value}))}
                    className="w-full h-24 border border-slate-200 rounded-xl p-4 bg-slate-50 text-xs font-medium focus:bg-white focus:border-orange-500 outline-none transition-all resize-none" 
                    placeholder="Kết quả phân tích..." 
                />

                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    <div className="space-y-1">
                        <label className="text-[10px] font-black text-slate-500 uppercase px-1">Phong cách</label>
                        <select 
                            value={state.style} 
                            onChange={e => setState((p:any)=>({...p, style: e.target.value}))}
                            className="w-full p-3 border border-slate-200 rounded-xl bg-slate-50 text-xs font-bold outline-none focus:border-orange-500"
                        >
                            {STYLES.map(s => <option key={s.id} value={s.id}>{s.label}</option>)}
                        </select>
                    </div>
                    <div className="space-y-1">
                        <label className="text-[10px] font-black text-slate-500 uppercase px-1">Giới tính</label>
                        <select 
                            value={state.gender} 
                            onChange={e => setState((p:any)=>({...p, gender: e.target.value}))}
                            className="w-full p-3 border border-slate-200 rounded-xl bg-slate-50 text-xs font-bold outline-none focus:border-orange-500"
                        >
                            <option value="Nữ">Nữ</option>
                            <option value="Nam">Nam</option>
                        </select>
                    </div>
                    <div className="space-y-1">
                        <label className="text-[10px] font-black text-slate-500 uppercase px-1">Vùng miền</label>
                        <select 
                            value={state.voice} 
                            onChange={e => setState((p:any)=>({...p, voice: e.target.value}))}
                            className="w-full p-3 border border-slate-200 rounded-xl bg-slate-50 text-xs font-bold outline-none focus:border-orange-500"
                        >
                            <option value="Miền Bắc">Miền Bắc</option>
                            <option value="Miền Nam">Miền Nam</option>
                        </select>
                    </div>
                    <div className="space-y-1">
                        <label className="text-[10px] font-black text-slate-500 uppercase px-1">Thời lượng (Scenes)</label>
                        <select 
                            value={state.segmentCount} 
                            onChange={e => setState((p:any)=>({...p, segmentCount: parseInt(e.target.value)}))}
                            className="w-full p-3 border border-slate-200 rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none font-bold text-orange-600"
                        >
                            {SCENE_COUNT_OPTIONS.map(opt => (
                                <option key={opt.count} value={opt.count}>{opt.label}</option>
                            ))}
                        </select>
                    </div>
                </div>

