                <div className="space-y-4">
                    <label className="text-[10px] font-black text-slate-500 uppercase px-1">4. Mô tả nhân vật & Trang phục:</label>
                    <div className="grid grid-cols-1 md:grid-cols-12 gap-6 items-start">
