                                ) : (
                                    <div className="text-center p-2">
                                        <svg className="w-6 h-6 text-slate-300 mx-auto mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" /></svg>
                                        <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Trang phục</span>
                                    </div>
                                )}
                                <input type="file" ref={outfitInputRef} onChange={handleOutfitUpload} className="hidden" accept="image/*" />
                            </div>
                            {(state.outfitFile || state.outfitPreviewUrl?.startsWith('data:')) && (
                                <button
                                    onClick={handleExtractOutfit}
                                    disabled={state.isExtractingOutfit}
                                    className="w-full py-2 bg-blue-600 text-white text-[9px] font-black rounded-lg hover:bg-blue-700 transition-all uppercase disabled:opacity-50"
                                >
                                    {state.isExtractingOutfit ? "Đang tách..." : "Tách trang phục"}
