                        <div className="md:col-span-9 space-y-4">
                            <div className="space-y-1">
                                <label className="text-[9px] font-bold text-slate-400 uppercase">Ghi chú nhân vật:</label>
                                <textarea 
                                    value={state.characterDescription}
                                    onChange={e => setState((p:any)=>({...p, characterDescription: e.target.value}))}
                                    placeholder="Tuổi tác, ngoại hình chi tiết..."
                                    className="w-full h-24 p-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-medium focus:bg-white focus:border-orange-500 outline-none transition-all resize-none"
                                />
                            </div>
                            <div className="space-y-1">
                                <label className="text-[9px] font-bold text-slate-400 uppercase">Bối cảnh / Lưu ý:</label>
                                <textarea 
                                    value={state.contextNote}
                                    onChange={e => setState((p:any)=>({...p, contextNote: e.target.value}))}
                                    placeholder="Không gian phòng, cấm kỵ..."
                                    className="w-full h-20 p-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-medium focus:bg-white focus:border-orange-500 outline-none transition-all resize-none"
                                />
                            </div>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-1">
                        <label className="text-[10px] font-black text-slate-500 uppercase px-1">Phong cách ảnh</label>
                        <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-200">
                          <button onClick={() => setState((p:any)=>({...p, imageStyle: 'Realistic'}))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${state.imageStyle === 'Realistic' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>Chân thực</button>
                          <button onClick={() => setState((p:any)=>({...p, imageStyle: '3D'}))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${state.imageStyle === '3D' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>3D Animation</button>
                        </div>
                    </div>
                </div>

                <button 
                    onClick={handleGenScript} 
                    disabled={state.isGeneratingScript || !state.analysis} 
                    className="w-full py-5 bg-orange-600 text-white font-black rounded-xl shadow-lg hover:bg-orange-700 transition-all flex items-center justify-center gap-3 group disabled:opacity-50 uppercase text-sm tracking-widest"
                >
                    {state.isGeneratingScript ? "Đang xử lý..." : "Tạo phiên bản POV"}
                    <svg className="w-5 h-5 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 10V3L4 14H11V21L20 10H13Z" /></svg>
                </button>
            </div>
        </div>

        {(state.segments && state.segments.length > 0) && (
            <div className="space-y-10 pb-32">
                <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-sm">
                    <h3 className="text-sm font-black text-white uppercase tracking-tight">KẾT QUẢ CHIẾN DỊCH POV</h3>
                    <p className="text-[10px] font-bold text-orange-500 uppercase tracking-widest">Đã tạo xong {state.segments.length} cảnh ({state.segments.length * 8}s)</p>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
                    {state.segments.map((seg: any) => {
                        const charCount = seg.content?.length || 0;
                        return (
                            <div key={seg.id} className="bg-white rounded-[32px] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full hover:shadow-xl transition-all group">
                                <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center"><span className="text-[10px] font-black text-slate-500 uppercase">Cảnh {seg.id}</span></div>
                                <div className="relative aspect-[9/16] bg-slate-100 group-hover:brightness-105 transition-all">
                                    {seg.image?.url ? <img src={seg.image.url} className="w-full h-full object-cover" /> : <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center opacity-30"><span className="text-[10px] font-black uppercase tracking-widest">Sẵn sàng tạo ảnh</span></div>}
                                </div>
                                <div className="p-5 flex flex-col flex-1 gap-4">
                                    <div className="space-y-1">
                                        <div className="flex justify-between items-center mb-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Kịch bản:</label><span className={`text-[9px] font-bold px-2 py-0.5 rounded-full ${charCount > 190 ? 'bg-red-100 text-red-600' : 'bg-slate-100 text-slate-400'}`}>{charCount} / 190</span></div>
                                        <textarea value={seg.content} onChange={e => setState((p:any)=>({...p, segments: p.segments.map((s:any)=>s.id===seg.id?{...s, content: e.target.value}:s)}))} className="w-full h-24 p-3 text-xs font-bold text-slate-700 bg-slate-50 border border-slate-100 rounded-xl outline-none resize-none leading-relaxed focus:bg-white" />
                                    </div>
                                    <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase">Ghi chú sửa ảnh:</label><textarea value={seg.image?.regenNote || ''} onChange={e => setState((p:any)=>({...p, segments: p.segments.map((s:any)=>s.id===seg.id?{...s, image:{...s.image, regenNote: e.target.value}}:s)}))} placeholder="VD: Góc quay..." className="w-full h-12 p-3 text-[9px] border border-dashed border-slate-200 rounded-xl outline-none resize-none" /></div>
                                    <div className="mt-auto flex gap-2">
                                        <button onClick={() => handleGenImage(seg.id)} disabled={seg.image?.loading} className="flex-1 py-3 bg-slate-900 text-white text-[9px] font-black rounded-xl hover:bg-black transition-all uppercase">{(seg.image && seg.image.url) ? "Tạo lại" : "Tạo Ảnh"}</button>
                                        <button onClick={() => handleGenPrompt(seg.id)} disabled={seg.videoPrompt?.loading} className="flex-1 py-3 bg-orange-50 text-orange-700 text-[9px] font-black rounded-xl border border-orange-100 uppercase">Prompt</button>
                                    </div>
                                </div>
                                {(seg.videoPrompt && seg.videoPrompt.visible) && (
                                    <div className="p-4 bg-slate-900 border-t border-slate-800 animate-slideUp">
                                        <div className="flex justify-between items-center mb-2"><span className="text-[8px] text-orange-500 font-bold uppercase">VEO-3 Prompt</span><button onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} className="text-[8px] text-white font-black underline uppercase">Copy</button></div>
                                        <div className="text-[9px] text-slate-300 line-clamp-3 italic">"{seg.videoPrompt.text}"</div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
                <div className="flex flex-col items-center gap-12 py-12">
                    <button onClick={handleBulkPrompt} className="px-12 py-5 bg-slate-900 text-white font-black rounded-2xl shadow-2xl hover:scale-105 active:scale-95 transition-all text-lg flex items-center gap-4 uppercase tracking-widest">TỰ ĐỘNG VIẾT TẤT CẢ PROMPTS<svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14H11V21L20 10H13Z" /></svg></button>
                    {hasAnyMedia && (
                        <div className="flex flex-col md:flex-row items-center justify-center gap-4 border-t border-slate-200 w-full pt-12">
                            <button onClick={downloadAllImagesZip} className="w-full md:w-auto px-12 py-5 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:bg-black transition-all active:scale-[0.98] flex items-center justify-center gap-3 uppercase tracking-widest text-base"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>Tải toàn bộ ảnh (ZIP)</button>
                            <button onClick={downloadAllPromptsTxt} className="w-full md:w-auto px-12 py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl hover:bg-orange-700 transition-all active:scale-[0.98] flex items-center justify-center gap-3 uppercase tracking-widest text-base"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1.01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>Tải File Prompt (.txt)</button>
                        </div>
                    )}
                </div>
            </div>
        )}
    </div>
  );
};

export default VideoPovModule;

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/videoPovService';
import { PovScriptSegment } from '../types';

declare var JSZip: any;

const STYLES = [
    { id: 'tâm sự trải lòng', label: 'Tâm sự trải lòng (Deep/Emotional)' },
