export const generatePovSegments = async (
  analysis: string, 
  style: string, 
  count: number, 
  gender: string, 
  voice: string, 
  charDesc: string, 
  contextNote: string
): Promise<string[]> => {
  const ai = getAiClient();

  let dialectInstruction = voice === 'Miền Bắc' 
    ? "NGÔN NGỮ CHUẨN NGƯỜI HÀ NỘI (MIỀN BẮC): nhé, ạ, thế, đấy, chứ."
    : "NGÔN NGỮ CHUẨN NGƯỜI SÀI GÒN (MIỀN NAM): nha, nè, nghen, thiệt, hông.";

  const prompt = `
    Dựa trên bản phân tích nội dung sau: "${analysis}".
    Hãy tạo ra một kịch bản POV mới hoàn toàn, phong cách: "${style}".

    YÊU CẦU VỀ NỘI DUNG KỊCH BẢN (CỰC KỲ QUAN TRỌNG):
    1. Kịch bản CHỈ bao gồm lời thoại (dialogue) hoặc lời dẫn truyện (narration).
    2. TUYỆT ĐỐI KHÔNG mô tả nhân vật hay bối cảnh vào nội dung kịch bản.
    3. TUYỆT ĐỐI KHÔNG viết các ghi chú hành động hoặc cảm xúc trong ngoặc.

    YÊU CẦU NGÔN NGỮ:
    - Vùng miền: ${voice}. ${dialectInstruction}
    - Xưng hô "mình", "em" một cách tự nhiên.

    YÊU CẦU CẤU TRÚC:
    - Chia kịch bản thành đúng ${count} đoạn nhỏ.
    - Mỗi đoạn từ 150 đến 190 ký tự.
    - Trả về JSON mảng chuỗi.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: { 
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) { return []; }
};

export const regeneratePovSegment = async (
  analysis: string,
  style: string,
  gender: string,
  voice: string,
  charDesc: string,
  contextNote: string,
  currentContent: string,
  allSegments: string[]
): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Hãy viết lại ĐOẠN kịch bản POV sau đây cho hay hơn và viral hơn.
    Nội dung cũ: "${currentContent}"
    Toàn bộ kịch bản hiện tại để đảm bảo tính liên kết: "${allSegments.join(' ')}"

    YÊU CẦU:
    1. Chỉ trả về lời thoại mới.
    2. Độ dài: 150 - 190 ký tự.
    3. Giọng: ${voice}. Phong cách: ${style}.
    4. Không thêm mô tả nhân vật hay bối cảnh.
  `;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] }
    });
    return response.text?.trim() || currentContent;
  } catch (e) { return currentContent; }
};

export const generatePovImage = async (
  script: string, 
  facePart: any | null, 
  gender: string, 
  charDesc: string,
  regenNote: string = "",
  imageStyle: 'Realistic' | '3D' = 'Realistic',
  contextNote: string = "",
  outfitPart: any | null = null
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const baseStyle = is3D 
    ? "3D Animation Pixar/Disney style, vibrant colors, expressive 3D character design, high-quality CGI."
    : "Photorealistic RAW PHOTO, 8k resolution, authentic textures, cinematic lighting.";

  const faceInstruction = facePart 
    ? "Maintain the exact facial features of the person in the provided face reference image." 
    : `Appearance: Vietnamese ${gender}. ${charDesc}`;

  const outfitInstruction = outfitPart 
    ? "The character MUST wear the exact outfit shown in the OUTFIT_REFERENCE image. Match style and colors perfectly."
    : `The character wears an outfit matching: ${charDesc}`;

  const prompt = `
    ${baseStyle} 9:16 aspect ratio.
    Subject: ${faceInstruction}.
    ${outfitInstruction}
    Action/Scene: "${script}".

    ENVIRONMENT: ${contextNote || 'Natural lifestyle setting'}.
    STRICT NO-TEXT & NO-UI POLICY. NO CHILDREN.
    ${regenNote ? `Additional Feedback: ${regenNote}` : ""}
  `;

  const parts: any[] = [{ text: prompt }];
  if (facePart) parts.push({ inlineData: facePart });
  if (outfitPart) parts.push({ inlineData: outfitPart });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (error) { throw error; }
};

export const formatVideoPrompt = async (
  script: string, 
  gender: string, 
  voice: string, 
  charDesc: string, 
  contextNote: string,
  imageStyle: 'Realistic' | '3D' = 'Realistic',
  generatedImageBase64?: string
): Promise<string> => {
    const ai = getAiClient();
    const is3D = imageStyle === '3D';
    const voiceTag = voice === 'Miền Bắc' ? 'Northern Vietnamese' : 'Southern Vietnamese';
    const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

    const systemPrompt = `
    Viết 1 dòng video prompt duy nhất cho VEO-3.
    Dựa trên ảnh: Nhân vật người Việt ${gender}, ${is3D ? "3D Pixar style" : "Realistic photo"}.
    Hành động: Nói chuyện biểu cảm khớp lời thoại: "${script}".
    Camera: Chuyển động Zoom/Pan mượt mà, tỉ lệ 9:16.
    Lời thoại: ✨ Model speaks in ${voiceTag} voice (${voiceGender}): "${script}"
    Thông số: 4K, 60fps, cinematic lighting.
    `;

    const parts: any[] = [{ text: systemPrompt }];
    if (generatedImageBase64) {
      parts.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });
    }

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: { parts }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
};

